# =============================================================================
# Internal Client
# =============================================================================


class _ImmyBotAPIClient:
    """Internal client implementation for ImmyBotAPI."""

    # Status codes that trigger automatic retry
    RETRYABLE_STATUS_CODES = {429, 500, 502, 503, 504}

    def __init__(
        self,
        base_url: str,
        session: requests.Session,
        timeout: float = 30.0,
        max_retries: int = 3,
        base_backoff: float = 1.0,
        max_backoff: float = 60.0,
    ):
        self.base_url = base_url.rstrip("/")
        self.session = session
        self.timeout = timeout
        self.max_retries = max_retries
        self.base_backoff = base_backoff
        self.max_backoff = max_backoff

    def _request_with_retry(
        self, method: str, url: str, **kwargs
    ) -> requests.Response:
        """Execute HTTP request with exponential backoff retry for transient failures."""
        kwargs.setdefault("timeout", self.timeout)
        last_response = None

        for attempt in range(self.max_retries + 1):
            response = self.session.request(method, url, **kwargs)
            last_response = response

            # Success or non-retryable error - return immediately
            if response.status_code not in self.RETRYABLE_STATUS_CODES:
                return response

            # Don't retry after the last attempt
            if attempt >= self.max_retries:
                break

            # Calculate wait time
            if response.status_code == 429:
                # Respect Retry-After header if present
                retry_after = response.headers.get("Retry-After")
                if retry_after:
                    try:
                        wait = float(retry_after)
                    except ValueError:
                        # Retry-After can be a date string, fall back to backoff
                        wait = self.base_backoff * (2 ** attempt)
                else:
                    wait = self.base_backoff * (2 ** attempt)
            else:
                # Exponential backoff for 5xx errors
                wait = self.base_backoff * (2 ** attempt)

            # Cap the wait time
            wait = min(wait, self.max_backoff)
            time.sleep(wait)

        return last_response

    def _auto_convert(self, data):
        """Automatically convert dicts to DotDict for dot notation access."""
        if data is None:
            return None
        if isinstance(data, list):
            return [self._auto_convert(item) for item in data]
        if isinstance(data, dict):
            return DotDict(data)
        return data

    def list_application_locks(self, **kwargs) -> List[ApplicationLocksResponse]:
        """GET /api/v1/application-locks"""
        url = f"{self.base_url}/api/v1/application-locks"
        response = self._request_with_retry("GET", url, params=kwargs)
        try:
            response.raise_for_status()
        except requests.exceptions.HTTPError as e:
            body = e.response.text[:1000] if e.response else "No response body"
            raise SDKError(
                f"HTTP {e.response.status_code}: {body}",
                status_code=e.response.status_code,
                response_body=body,
            )
        try:
            result = response.json() if response.content else None
        except requests.exceptions.JSONDecodeError:
            raise SDKError(
                f"Invalid JSON response (HTTP {response.status_code}): {response.text[:500]}",
                status_code=response.status_code,
                response_body=response.text[:1000],
            )
        return self._auto_convert(result)

